function transform(message, context) {
  const ids = message.payload?.ids || [];

  const legacyIdCode = context.get('legacyIdCode');
  const workdayIdCode = context.get('workdayIdCode');
  const studentNetIdCode = context.get('studentNetIdCode');
  const employeeNetIdCode = context.get('employeeNetIdCode');

  const legacyIdType = ids.find(entry => entry.code === legacyIdCode)?.id || null;
  if (legacyIdType) context.set('legacyIdType', legacyIdType);

  const workdayIdType = ids.find(entry => entry.code === workdayIdCode)?.id || null;
  if (workdayIdType) context.set('workdayIdType', workdayIdType);

  const studentNetIdType = ids.find(entry => entry.code === studentNetIdCode)?.id || null;
  if (studentNetIdType) context.set('studentNetIdType', studentNetIdType);

  const employeeNetIdType = ids.find(entry => entry.code === employeeNetIdCode)?.id || null;
  if (employeeNetIdType) context.set('employeeNetIdType', employeeNetIdType);

  const personId = context.get('testUserId') || context.get('__user')?.id;
  if (personId) context.set('personId', personId);

  return { message, context };
}

function transform(message, context) {
  const altCreds = message.payload?.alternativeCredentials || [];
  const creds = message.payload?.credentials || [];

  const legacyIdType = context.get('legacyIdType');
  const workdayIdType = context.get('workdayIdType');
  const bannerIdType = context.get('bannerIdType');
  const studentNetIdType = context.get('studentNetIdType');
  const employeeNetIdType = context.get('employeeNetIdType');

  const legacyId = altCreds.find(alt => alt.type?.id === legacyIdType)?.value;
  if (legacyId) context.set('legacyId', legacyId);

  const workdayId = altCreds.find(alt => alt.type?.id === workdayIdType)?.value;
  if (workdayId) context.set('workdayId', workdayId);

  const studentNetId = altCreds.find(alt => alt.type?.id === studentNetIdType)?.value;
  if (studentNetId) context.set('studentNetId', studentNetId);

  const employeeNetId = altCreds.find(alt => alt.type?.id === employeeNetIdType)?.value;
  if (employeeNetId) context.set('employeeNetId', employeeNetId);

  const bannerId = creds.find(cred => cred.type === bannerIdType)?.value;
  if (bannerId) context.set('bannerId', bannerId);

  return { message, context };
}

function transform(message, context) {
  return {
    bannerId: context.get('bannerId') || null,
    workdayId: context.get('workdayId') || null,
    studentNetId: context.get('studentNetId') || null,
    employeeNetId: context.get('employeeNetId') || null,
    legacyId: context.get('legacyId') || null
  };
}
